void capture_static_enum_info(const std::string &path, std::initializer_list<std::string_view> names, SeriesAccumulator *series) {
  if (series->enum_info.find(path) != series->enum_info.end()) {
    return;
  }
  EnumInfo info;
  info.names.reserve(names.size());
  for (std::string_view name : names) {
    info.names.emplace_back(name);
  }
  if (!info.names.empty()) {
    series->enum_info.emplace(path, std::move(info));
  }
}

